  "module_map": [
    {
      "module": "django.core.handlers",
      "responsibility": "Request/response pipeline core: BaseHandler orchestrates view dispatch; WSGIHandler/ASGIHandler adapt to servers; exception handling and middleware registry",
      "key_types": ["BaseHandler", "WSGIHandler", "ASGIHandler", "ExceptionMiddleware", "RequestNode"],
      "depends_on": ["django.http", "django.urls", "django.core.exceptions"]
    },
    {
      "module": "django.http",
      "responsibility": "HTTP abstractions: HttpRequest/HttpResponse envelope data structures; content negotiation and media handling",
      "key_types": ["HttpRequest", "HttpResponse", "QueryDict", "MediaType", "HttpHeaders"],
      "depends_on": []
    },
    {
      "module": "django.urls",
      "responsibility": "URL routing and resolution: URLResolver routes requests to callbacks; RegexPattern/URLPattern define route patterns; ResolverMatch provides matched route info",
      "key_types": ["URLResolver", "URLPattern", "RegexPattern", "ResolverMatch"],
      "depends_on": ["django.http"]
    },
    {
      "module": "django.db.models",
      "responsibility": "ORM core: Model base class; field systems; querysets and database operations; model instantiation and saving lifecycle",
      "key_types": ["Model", "QuerySet", "ModelBase", "Field"],
      "depends_on": ["django.db.backends", "django.core.exceptions"]
    },
    {
      "module": "django.db.backends",
      "responsibility": "Database backend abstraction and query execution: connection management; cursor handling; transaction control; SQL compilation",
      "key_types": ["BaseDatabaseWrapper", "DatabaseIntrospection", "CursorWrapper", "DatabaseClient"],
      "depends_on": ["django.db.models.query"]
    },
    {
      "module": "django.middleware",
      "responsibility": "Middleware registry and common security/functional middleware: CSRF protection; clickjacking protection; XSS handling",
      "key_types": ["CsrfViewMiddleware", "XFrameOptionsMiddleware"],
      "depends_on": ["django.core.handlers"]
    },
    {
      "module": "django.contrib",
      "responsibility": "Contrib apps infrastructure and reusable components: auth, admin, sessions, messages, staticfiles, etc.; extensible via django.contrib.contenttypes framework",
      "key_types": ["ContentType"],
      "depends_on": ["django.apps", "django.db.models"]
    },
    {
      "module": "django.apps",
