      "key_types": ["AppConfig", "Apps"],
      "depends_on": []
    },
    {
      "module": "django.conf",
      "responsibility": "Settings and configuration system: Settings module; LazyObject patterns; configuration defaults and validation",
      "key_types": ["Settings", "LazySettings"],
      "depends_on": []
    },
    {
      "module": "django.template",
      "responsibility": "Template engine and rendering: Engine registry; context processors; template loading and caching",
      "key_types": ["Engine", "Context", "Template"],
      "depends_on": []
